// Leer datos del webhook y la plantilla de MongoDB
const webhookData = $('Webhook').first().json.body;
const template = $('MongoDB — Buscar plantilla').first().json;

const attackId = webhookData.attack_id;
const parameters = webhookData.parameters || {};
const companyName = webhookData.company_name || 'Empresa Auditada';
const reportId = 'CS-RPT-' + new Date().toISOString().slice(0,10) + '-' + attackId;

// Función para reemplazar {{variables}} con valores reales del formulario
function buildCommand(template_str, params) {
  if (!template_str) return '';
  return Object.entries(params).reduce((cmd, [key, value]) => {
    return cmd.replace(new RegExp('\\{\\{' + key + '\\}\\}', 'g'), value);
  }, template_str);
}

// Construir comando de ataque con parámetros del usuario
const attackCommand = buildCommand(template.command, parameters);

// Si target_ip está vacío, usar variante sin -d
const finalCommand = parameters.target_ip && parameters.target_ip.trim() !== ''
  ? buildCommand(template.command_alt || template.command, parameters)
  : attackCommand;

// Construir comando del logger (traza para Wazuh)
const loggerCommand = buildCommand(template.logger_command, parameters);

// Timestamp de inicio para correlación con Wazuh
const startTimestamp = new Date().toISOString();

return [{
  json: {
    attack_id: attackId,
    attack_name: template.name,
    mitre_id: template.mitre_id,
    risk_level: template.risk_level,
    wazuh_rule_id: template.wazuh_rule_id,
    description: template.description,
    command: finalCommand,
    logger_command: loggerCommand,
    parameters: parameters,
    company_name: companyName,
    report_id: reportId,
    start_timestamp: startTimestamp
  }
}];
